"use client";
/* ================================================================
   Auth Layout — Split-screen design for login / register / forgot
   Left: Brand panel  |  Right: Form
   ================================================================ */
import { useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuthStore } from "@/store/authStore";

export default function AuthLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const router = useRouter();
  const { isAuthenticated, isLoading } = useAuthStore();

  // ─── Redirect to dashboard if already logged in ─────────────
  useEffect(() => {
    if (!isLoading && isAuthenticated) {
      router.replace("/dashboard");
    }
  }, [isAuthenticated, isLoading, router]);

  if (isLoading) {
    return (
      <div
        className="gum-auth"
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          minHeight: "100vh",
        }}
      >
        <i
          className="fa-solid fa-spinner fa-spin"
          style={{ fontSize: 32, color: "var(--gum-primary)" }}
        />
      </div>
    );
  }

  if (isAuthenticated) return null;

  return (
    <div className="gum-auth">
      {/* ─── Left Brand Panel ─────────────────────────────── */}
      <div className="gum-auth__brand">
        <div className="gum-auth__brand-inner">
          <div
            style={{
              width: 72,
              height: 72,
              borderRadius: 16,
              background: "rgba(255,255,255,0.2)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 32,
              fontWeight: 700,
              color: "#fff",
              marginBottom: 24,
            }}
          >
            G
          </div>
          <h1
            style={{
              fontSize: 28,
              fontWeight: 700,
              color: "#fff",
              marginBottom: 12,
            }}
          >
            GrowUpMore
          </h1>
          <p
            style={{
              fontSize: 15,
              color: "rgba(255,255,255,0.8)",
              lineHeight: 1.6,
              maxWidth: 320,
              textAlign: "center",
            }}
          >
            Enterprise Administration Portal — Manage users, roles, permissions,
            and system configuration.
          </p>
        </div>
      </div>

      {/* ─── Right Form Panel ─────────────────────────────── */}
      <div className="gum-auth__form">{children}</div>
    </div>
  );
}
